//! Transaction bundle types for unified block building.
//!
//! This module provides the [`TxBundle`] enum which represents different types of
//! transactions that can be included in a block. All tip-paying transactions are
//! collected together and sorted by tip for optimal block building.

mod tests {
    use super::*;

    #[test]
    fn test_tx_source_equality() {
        assert_eq!(TxSource::Scheduled, TxSource::Scheduled);
        assert_ne!(TxSource::Scheduled, TxSource::Regular);
    }
}
